class Command {
public:
    virtual ~Command() = default;
    virtual void execute() = 0;
    virtual void undo() = 0;
};

// ====== Receiver ======
class Light {
    std::string location_;
    bool isOn_ = false;
public:
    explicit Light(std::string loc) : location_(std::move(loc)) {}
    void on()  { isOn_ = true;  std::cout << location_ << " light ON\n"; }
    void off() { isOn_ = false; std::cout << location_ << " light OFF\n"; }
    bool isOn() const { return isOn_; }
};

// ====== Concrete Command ======
class LightOnCommand : public Command {
    Light& light_;
    bool wasOn_; // saved state for undo
public:
    explicit LightOnCommand(Light& light) : light_(light), wasOn_(false) {}
    void execute() override {
        wasOn_ = light_.isOn(); // save BEFORE
        light_.on();
    }
    void undo() override {
        if (!wasOn_) light_.off(); // restore previous state
    }
};

class LightOffCommand : public Command {
    Light& light_;
    bool wasOn_;
public:
    explicit LightOffCommand(Light& light) : light_(light), wasOn_(false) {}
    void execute() override {
        wasOn_ = light_.isOn();
        light_.off();
    }
    void undo() override {
        if (wasOn_) light_.on();
    }
};

