#include <iostream>
#include <memory>
#include <vector>
#include <stack>
#include <stdexcept>
#include <string>

class Command {
public:
    virtual ~Command() = default;
    virtual void execute() = 0;
    virtual void undo() = 0;
};

// ====== Receivers ======
class Account {
    std::string name_;
    double balance_;
public:
    Account(std::string name, double balance)
        : name_(std::move(name)), balance_(balance) {}
    void withdraw(double amount) {
        if (balance_ < amount)
            throw std::runtime_error("Insufficient funds in " + name_);
        balance_ -= amount;
        std::cout << name_ << ": withdrew $" << amount
                  << " (balance: $" << balance_ << ")\n";
    }
    void deposit(double amount) {
        balance_ += amount;
        std::cout << name_ << ": deposited $" << amount
                  << " (balance: $" << balance_ << ")\n";
    }
    double getBalance() const { return balance_; }
};

// ====== Concrete Command ======
class TransferCommand : public Command {
    Account& from_;
    Account& to_;
    double amount_;
    bool executed_ = false;
public:
    TransferCommand(Account& from, Account& to, double amount)
        : from_(from), to_(to), amount_(amount) {}
    void execute() override {
        from_.withdraw(amount_);
        to_.deposit(amount_);
        executed_ = true;
    }
    void undo() override {
        if (executed_) {
            to_.withdraw(amount_);
            from_.deposit(amount_);
            executed_ = false;
        }
    }
};

// ====== Macro Command (Composite + Command) ======
class MacroCommand : public Command {
    std::vector<std::shared_ptr<Command>> commands_;
    std::stack<std::shared_ptr<Command>> executed_;
public:
    void addCommand(std::shared_ptr<Command> cmd) {
        commands_.push_back(std::move(cmd));
    }
    void execute() override {
        try {
            for (auto& cmd : commands_) {
                cmd->execute();
                executed_.push(cmd);
            }
        } catch (const std::exception& e) {
            std::cout << "FAILED: " << e.what() << " — ROLLING BACK\n";
            while (!executed_.empty()) {
                executed_.top()->undo();
                executed_.pop();
            }
            throw;
        }
    }
    void undo() override {
        while (!executed_.empty()) {
            executed_.top()->undo();
            executed_.pop();
        }
    }
};

int main() {
    Account alice("Alice", 1000);
    Account bob("Bob", 500);
    Account charlie("Charlie", 200);

    auto macro = std::make_shared<MacroCommand>();
    macro->addCommand(std::make_shared<TransferCommand>(alice, bob, 300));
    macro->addCommand(std::make_shared<TransferCommand>(bob, charlie, 1500)); // will fail!

    try {
        macro->execute();
    } catch (...) {
        std::cout << "\nAfter rollback:\n";
        std::cout << "Alice: $" << alice.getBalance() << "\n";   // $1000
        std::cout << "Bob: $" << bob.getBalance() << "\n";       // $500
        std::cout << "Charlie: $" << charlie.getBalance() << "\n"; // $200
    }
    return 0;
}

