#include <string>

class Command {
public:
    virtual ~Command() = default;
    virtual void execute() = 0;
    virtual void undo() = 0;
    virtual std::string name() const = 0;
};

class PrintCommand : public Command {
    std::string message_;
public:
    explicit PrintCommand(std::string msg) : message_(std::move(msg)) {}
    void execute() override { std::cout << "Executing: " << message_ << "\n"; }
    void undo() override { std::cout << "Undoing: " << message_ << "\n"; }
    std::string name() const override { return message_; }
};

struct ScheduledTask {
    std::shared_ptr<Command> command;
    int priority; // lower number = higher priority
    bool operator>(const ScheduledTask& other) const {
        return priority > other.priority;
    }
};

class TaskScheduler {
    std::priority_queue<ScheduledTask, std::vector<ScheduledTask>,
                        std::greater<ScheduledTask>> queue_;
public:
    void schedule(std::shared_ptr<Command> cmd, int priority) {
        queue_.push({std::move(cmd), priority});
    }
    void executeNext() {
        if (!queue_.empty()) {
            queue_.top().command->execute();
            queue_.pop();
        }
    }
    void executeAll() {
        while (!queue_.empty()) executeNext();
    }
};

int main() {
    TaskScheduler scheduler;
    scheduler.schedule(std::make_shared<PrintCommand>("Low priority task"), 3);
    scheduler.schedule(std::make_shared<PrintCommand>("URGENT task"), 1);
    scheduler.schedule(std::make_shared<PrintCommand>("Medium task"), 2);
    scheduler.executeAll();
    // Output: URGENT → Medium → Low
    return 0;
}

