import java.util.PriorityQueue;

interface Command {
    void execute();
    void undo();
    String name();
}

class PrintCommand implements Command {
    private String message;
    public PrintCommand(String msg) { this.message = msg; }
    public void execute() { System.out.println("Executing: " + message); }
    public void undo() { System.out.println("Undoing: " + message); }
    public String name() { return message; }
}

class ScheduledTask implements Comparable<ScheduledTask> {
    Command command;
    int priority;
    ScheduledTask(Command cmd, int priority) {
        this.command = cmd;
        this.priority = priority;
    }
    public int compareTo(ScheduledTask other) {
        return Integer.compare(this.priority, other.priority);
    }
}

class TaskScheduler {
    private PriorityQueue<ScheduledTask> queue = new PriorityQueue<>();

    public void schedule(Command cmd, int priority) {
        queue.offer(new ScheduledTask(cmd, priority));
    }
    public void executeNext() {
        ScheduledTask task = queue.poll();
        if (task != null) task.command.execute();
    }
    public void executeAll() {
        while (!queue.isEmpty()) executeNext();
    }
}

public class Main {
    public static void main(String[] args) {
        TaskScheduler scheduler = new TaskScheduler();
        scheduler.schedule(new PrintCommand("Low priority task"), 3);
        scheduler.schedule(new PrintCommand("URGENT task"), 1);
        scheduler.schedule(new PrintCommand("Medium task"), 2);
        scheduler.executeAll();
        // Output: URGENT → Medium → Low
    }
}

