        std::cout << "Drew: " << shape << "\n";
    }
    void removeShape(const std::string& shape) {
        auto it = std::find(shapes_.begin(), shapes_.end(), shape);
        if (it != shapes_.end()) {
            shapes_.erase(it);
            std::cout << "Removed: " << shape << "\n";
        }
    }
    void display() const {
        std::cout << "Canvas: [";
        for (size_t i = 0; i < shapes_.size(); ++i) {
            std::cout << shapes_[i];
            if (i + 1 < shapes_.size()) std::cout << ", ";
        }
        std::cout << "]\n";
    }
};

class DrawCommand : public Command {
    Canvas& canvas_;
    std::string shape_;
public:
    DrawCommand(Canvas& c, std::string shape)
        : canvas_(c), shape_(std::move(shape)) {}
    void execute() override { canvas_.addShape(shape_); }
    void undo() override { canvas_.removeShape(shape_); }
};

