#include <memory>
#include <vector>
#include <string>
#include <chrono>
#include <iomanip>
#include <sstream>

// ====== Event (Persistent Command) ======
class Event {
public:
    virtual ~Event() = default;
    virtual void apply(class BankAccount& account) = 0;
    virtual std::string describe() const = 0;

    std::string timestamp;
    Event() {
        auto now = std::chrono::system_clock::now();
        auto time = std::chrono::system_clock::to_time_t(now);
        std::stringstream ss;
        ss << std::put_time(std::localtime(&time), "%H:%M:%S");
        timestamp = ss.str();
    }
};

// ====== Aggregate (Receiver) ======
class BankAccount {
    std::string owner_;
    double balance_ = 0;
public:
    explicit BankAccount(std::string owner) : owner_(std::move(owner)) {}
    void credit(double amount) { balance_ += amount; }
    void debit(double amount) {
        if (balance_ < amount) throw std::runtime_error("Insufficient funds");
        balance_ -= amount;
    }
    double getBalance() const { return balance_; }
    std::string getOwner() const { return owner_; }
};

// ====== Concrete Events ======
class DepositEvent : public Event {
    double amount_;
public:
    explicit DepositEvent(double amount) : amount_(amount) {}
    void apply(BankAccount& account) override { account.credit(amount_); }
    std::string describe() const override {
        return "[" + timestamp + "] DEPOSIT $" + std::to_string((int)amount_);
    }
};

class WithdrawEvent : public Event {
    double amount_;
public:
    explicit WithdrawEvent(double amount) : amount_(amount) {}
    void apply(BankAccount& account) override { account.debit(amount_); }
    std::string describe() const override {
        return "[" + timestamp + "] WITHDRAW $" + std::to_string((int)amount_);
    }
};

// ====== Event Store (Persistent Command Log) ======
class EventStore {
    std::vector<std::shared_ptr<Event>> events_;
public:
    void append(std::shared_ptr<Event> event) {
        events_.push_back(std::move(event));
    }

    // Replay ALL events to rebuild current state
    BankAccount replay(const std::string& owner) const {
        BankAccount account(owner);
        for (const auto& event : events_) {
            event->apply(account);
        }
        return account;
    }

    // Replay up to N events (time travel!)
    BankAccount replayUpTo(const std::string& owner, size_t n) const {
        BankAccount account(owner);
        for (size_t i = 0; i < n && i < events_.size(); ++i) {
            events_[i]->apply(account);
        }
        return account;
    }

    // Audit trail
    void printAuditLog() const {
        std::cout << "=== AUDIT LOG ===\n";
        for (const auto& event : events_) {
            std::cout << event->describe() << "\n";
        }
    }

    size_t size() const { return events_.size(); }
};

int main() {
    EventStore store;

    // Record events (commands)
    store.append(std::make_shared<DepositEvent>(1000));
    store.append(std::make_shared<DepositEvent>(500));
    store.append(std::make_shared<WithdrawEvent>(200));
    store.append(std::make_shared<DepositEvent>(300));

    // Rebuild current state by replaying all events
    auto current = store.replay("Alice");
    std::cout << "Current balance: $" << current.getBalance() << "\n"; // $1600

    // Time travel: what was the balance after 2 transactions?
    auto historical = store.replayUpTo("Alice", 2);
    std::cout << "After 2 events: $" << historical.getBalance() << "\n"; // $1500

    // Full audit trail
    store.printAuditLog();
    return 0;
}

