import java.time.LocalTime;
import java.time.format.DateTimeFormatter;
import java.util.*;

// ====== Event (Persistent Command) ======
abstract class Event {
    final String timestamp = LocalTime.now().format(DateTimeFormatter.ofPattern("HH:mm:ss"));
    abstract void apply(BankAccount account);
    abstract String describe();
}

// ====== Aggregate (Receiver) ======
class BankAccount {
    private String owner;
    private double balance = 0;

    public BankAccount(String owner) { this.owner = owner; }
    public void credit(double amount) { balance += amount; }
    public void debit(double amount) {
        if (balance < amount) throw new RuntimeException("Insufficient funds");
        balance -= amount;
    }
    public double getBalance() { return balance; }
}

// ====== Concrete Events ======
class DepositEvent extends Event {
    private double amount;
    DepositEvent(double amount) { this.amount = amount; }
    void apply(BankAccount account) { account.credit(amount); }
    String describe() { return String.format("[%s] DEPOSIT $%.0f", timestamp, amount); }
}

class WithdrawEvent extends Event {
    private double amount;
    WithdrawEvent(double amount) { this.amount = amount; }
    void apply(BankAccount account) { account.debit(amount); }
    String describe() { return String.format("[%s] WITHDRAW $%.0f", timestamp, amount); }
}

// ====== Event Store (Persistent Command Log) ======
class EventStore {
    private List<Event> events = new ArrayList<>();

    public void append(Event event) { events.add(event); }

    // Replay ALL events to rebuild current state
    public BankAccount replay(String owner) {
        BankAccount account = new BankAccount(owner);
        events.forEach(e -> e.apply(account));
        return account;
    }

    // Replay up to N events (time travel!)
    public BankAccount replayUpTo(String owner, int n) {
        BankAccount account = new BankAccount(owner);
        events.stream().limit(n).forEach(e -> e.apply(account));
        return account;
    }

    // Audit trail
    public void printAuditLog() {
        System.out.println("=== AUDIT LOG ===");
        events.forEach(e -> System.out.println(e.describe()));
    }
}

// ====== Client ======
public class EventSourcingDemo {
    public static void main(String[] args) {
        EventStore store = new EventStore();

        store.append(new DepositEvent(1000));
        store.append(new DepositEvent(500));
        store.append(new WithdrawEvent(200));
        store.append(new DepositEvent(300));

        // Current state by replaying all events
        BankAccount current = store.replay("Alice");
        System.out.printf("Current balance: $%.0f%n", current.getBalance()); // $1600

        // Time travel: balance after 2 events
        BankAccount historical = store.replayUpTo("Alice", 2);
        System.out.printf("After 2 events: $%.0f%n", historical.getBalance()); // $1500

        store.printAuditLog();
    }
}

