#include <iostream>
#include <memory>
#include <stack>
#include <vector>
#include <string>
#include <optional>

class Command {
public:
    virtual ~Command() = default;
    virtual void execute() = 0;
    virtual void undo() = 0;
    virtual std::string notation() const = 0;
};

struct Piece {
    std::string name; // "WK" = White King, "BR" = Black Rook, etc.
};

class Board {
    std::optional<Piece> squares_[8][8];
public:
    void placePiece(int row, int col, Piece piece) {
        squares_[row][col] = piece;
    }
    std::optional<Piece> removePiece(int row, int col) {
        auto piece = squares_[row][col];
        squares_[row][col] = std::nullopt;
        return piece;
    }
    std::optional<Piece> getPiece(int row, int col) const {
        return squares_[row][col];
    }
};

class MoveCommand : public Command {
    Board& board_;
    int fromRow_, fromCol_, toRow_, toCol_;
    std::optional<Piece> capturedPiece_;
    Piece movingPiece_;
public:
    MoveCommand(Board& board, int fr, int fc, int tr, int tc)
        : board_(board), fromRow_(fr), fromCol_(fc),
          toRow_(tr), toCol_(tc) {}

    void execute() override {
        movingPiece_ = *board_.removePiece(fromRow_, fromCol_);
        capturedPiece_ = board_.removePiece(toRow_, toCol_);
        board_.placePiece(toRow_, toCol_, movingPiece_);
        std::cout << movingPiece_.name << ": ("
                  << fromRow_ << "," << fromCol_ << ") -> ("
                  << toRow_ << "," << toCol_ << ")";
        if (capturedPiece_) std::cout << " captures " << capturedPiece_->name;
        std::cout << "\n";
    }
    void undo() override {
        board_.removePiece(toRow_, toCol_);
        board_.placePiece(fromRow_, fromCol_, movingPiece_);
        if (capturedPiece_) board_.placePiece(toRow_, toCol_, *capturedPiece_);
        std::cout << "Undo: " << movingPiece_.name << " back to ("
                  << fromRow_ << "," << fromCol_ << ")\n";
    }
    std::string notation() const override {
        return movingPiece_.name + "(" + std::to_string(fromRow_) + ","
               + std::to_string(fromCol_) + ")->("
               + std::to_string(toRow_) + "," + std::to_string(toCol_) + ")";
    }
};

class CastleCommand : public Command {
    std::shared_ptr<MoveCommand> kingMove_;
    std::shared_ptr<MoveCommand> rookMove_;
public:
    CastleCommand(std::shared_ptr<MoveCommand> king, std::shared_ptr<MoveCommand> rook)
        : kingMove_(std::move(king)), rookMove_(std::move(rook)) {}
    void execute() override {
        kingMove_->execute();
        rookMove_->execute();
        std::cout << "Castled!\n";
    }
    void undo() override {
        rookMove_->undo();
        kingMove_->undo();
        std::cout << "Castle undone!\n";
    }
    std::string notation() const override { return "O-O"; }
};

class GameController {
    std::stack<std::shared_ptr<Command>> undoStack_;
    std::stack<std::shared_ptr<Command>> redoStack_;
public:
    void makeMove(std::shared_ptr<Command> cmd) {
        cmd->execute();
        undoStack_.push(cmd);
        while (!redoStack_.empty()) redoStack_.pop();
    }
    void undo() {
        if (!undoStack_.empty()) {
            auto cmd = undoStack_.top(); undoStack_.pop();
            cmd->undo();
            redoStack_.push(cmd);
        }
    }
    void redo() {
        if (!redoStack_.empty()) {
            auto cmd = redoStack_.top(); redoStack_.pop();
            cmd->execute();
            undoStack_.push(cmd);
        }
    }
};

int main() {
    Board board;
    board.placePiece(0, 4, {"WK"});
    board.placePiece(0, 7, {"WR"});
    board.placePiece(6, 4, {"BP"});

    GameController game;

    // Normal move
    game.makeMove(std::make_shared<MoveCommand>(board, 6, 4, 4, 4));

    // Castle
    auto kingMove = std::make_shared<MoveCommand>(board, 0, 4, 0, 6);
    auto rookMove = std::make_shared<MoveCommand>(board, 0, 7, 0, 5);
    game.makeMove(std::make_shared<CastleCommand>(kingMove, rookMove));

    // Undo castle (both king and rook return)
    game.undo();

    // Redo castle
    game.redo();
    return 0;
}

