interface Command {
    void execute();
    void undo();
    String notation();
}

class Piece {
    String name;
    Piece(String name) { this.name = name; }
}

class Board {
    private Piece[][] squares = new Piece[8][8];
    public void placePiece(int row, int col, Piece piece) { squares[row][col] = piece; }
    public Piece removePiece(int row, int col) {
        Piece piece = squares[row][col];
        squares[row][col] = null;
        return piece;
    }
    public Piece getPiece(int row, int col) { return squares[row][col]; }
}

class MoveCommand implements Command {
    private Board board;
    private int fromRow, fromCol, toRow, toCol;
    private Piece capturedPiece;
    private Piece movingPiece;

    MoveCommand(Board board, int fr, int fc, int tr, int tc) {
        this.board = board;
        fromRow = fr; fromCol = fc; toRow = tr; toCol = tc;
    }
    public void execute() {
        movingPiece = board.removePiece(fromRow, fromCol);
        capturedPiece = board.removePiece(toRow, toCol);
        board.placePiece(toRow, toCol, movingPiece);
        System.out.printf("%s: (%d,%d)->(%d,%d)", movingPiece.name,
                          fromRow, fromCol, toRow, toCol);
        if (capturedPiece != null) System.out.print(" captures " + capturedPiece.name);
        System.out.println();
    }
    public void undo() {
        board.removePiece(toRow, toCol);
        board.placePiece(fromRow, fromCol, movingPiece);
        if (capturedPiece != null) board.placePiece(toRow, toCol, capturedPiece);
        System.out.println("Undo: " + movingPiece.name + " back to (" + fromRow + "," + fromCol + ")");
    }
    public String notation() {
        return movingPiece.name + "(" + fromRow + "," + fromCol + ")->(" + toRow + "," + toCol + ")";
    }
}

class CastleCommand implements Command {
    private MoveCommand kingMove, rookMove;
    CastleCommand(MoveCommand king, MoveCommand rook) {
        this.kingMove = king;
        this.rookMove = rook;
    }
    public void execute() {
        kingMove.execute();
        rookMove.execute();
        System.out.println("Castled!");
    }
    public void undo() {
        rookMove.undo();
        kingMove.undo();
        System.out.println("Castle undone!");
    }
    public String notation() { return "O-O"; }
}

class GameController {
    private Deque<Command> undoStack = new ArrayDeque<>();
    private Deque<Command> redoStack = new ArrayDeque<>();

    public void makeMove(Command cmd) {
        cmd.execute();
        undoStack.push(cmd);
        redoStack.clear();
    }
    public void undo() {
        if (!undoStack.isEmpty()) {
            Command cmd = undoStack.pop();
            cmd.undo();
            redoStack.push(cmd);
        }
    }
    public void redo() {
        if (!redoStack.isEmpty()) {
            Command cmd = redoStack.pop();
            cmd.execute();
            undoStack.push(cmd);
        }
    }
}

public class ChessGame {
    public static void main(String[] args) {
        Board board = new Board();
        board.placePiece(0, 4, new Piece("WK"));
        board.placePiece(0, 7, new Piece("WR"));
        board.placePiece(6, 4, new Piece("BP"));

        GameController game = new GameController();
        game.makeMove(new MoveCommand(board, 6, 4, 4, 4));

        MoveCommand kingMove = new MoveCommand(board, 0, 4, 0, 6);
        MoveCommand rookMove = new MoveCommand(board, 0, 7, 0, 5);
        game.makeMove(new CastleCommand(kingMove, rookMove));

        game.undo();  // Undo castle
        game.redo();  // Redo castle
    }
}

