#include <vector>
#include <stack>
#include <string>
#include <stdexcept>

class Migration {
public:
    virtual ~Migration() = default;
    virtual void up() = 0;
    virtual void down() = 0;
    virtual std::string version() const = 0;
    virtual std::string description() const = 0;
};

class CreateUsersTable : public Migration {
public:
    void up() override {
        std::cout << "Creating users table...\n";
    }
    void down() override {
        std::cout << "Dropping users table...\n";
    }
    std::string version() const override { return "001"; }
    std::string description() const override { return "Create users table"; }
};

class AddEmailColumn : public Migration {
public:
    void up() override {
        std::cout << "Adding email column to users...\n";
    }
    void down() override {
        std::cout << "Removing email column from users...\n";
    }
    std::string version() const override { return "002"; }
    std::string description() const override { return "Add email column"; }
};

class AddIndexOnEmail : public Migration {
public:
    void up() override {
        throw std::runtime_error("Index creation failed!");
    }
    void down() override {
        std::cout << "Dropping email index...\n";
    }
    std::string version() const override { return "003"; }
    std::string description() const override { return "Add index on email"; }
};

class MigrationRunner {
    std::vector<std::shared_ptr<Migration>> pending_;
    std::vector<std::shared_ptr<Migration>> applied_;
public:
    void addMigration(std::shared_ptr<Migration> m) {
        pending_.push_back(std::move(m));
    }

    void migrateUp() {
        std::stack<std::shared_ptr<Migration>> batch;
        try {
            for (auto& m : pending_) {
                std::cout << "[" << m->version() << "] " << m->description() << "\n";
                m->up();
                batch.push(m);
            }
            while (!batch.empty()) {
                applied_.push_back(batch.top());
                batch.pop();
            }
            pending_.clear();
            std::cout << "All migrations applied successfully!\n";
        } catch (const std::exception& e) {
            std::cout << "FAILED: " << e.what() << " — Rolling back batch...\n";
            while (!batch.empty()) {
                batch.top()->down();
                batch.pop();
            }
        }
    }

    void migrateDown(int n) {
        for (int i = 0; i < n && !applied_.empty(); ++i) {
            auto m = applied_.back();
            std::cout << "Rolling back [" << m->version() << "] "
                      << m->description() << "\n";
            m->down();
            applied_.pop_back();
        }
    }

    void getStatus() const {
        std::cout << "\n=== Migration Status ===\n";
        std::cout << "Applied: " << applied_.size() << "\n";
        for (const auto& m : applied_)
            std::cout << "  [" << m->version() << "] " << m->description() << "\n";
        std::cout << "Pending: " << pending_.size() << "\n";
        for (const auto& m : pending_)
            std::cout << "  [" << m->version() << "] " << m->description() << "\n";
    }
};

int main() {
    MigrationRunner runner;
    runner.addMigration(std::make_shared<CreateUsersTable>());
    runner.addMigration(std::make_shared<AddEmailColumn>());
    runner.addMigration(std::make_shared<AddIndexOnEmail>()); // will fail!

    runner.migrateUp();   // applies 1, 2, fails on 3, rolls back 2 and 1
    runner.getStatus();   // all still pending
    return 0;
}

