    private List<Migration> applied = new ArrayList<>();

    public void addMigration(Migration m) { pending.add(m); }

    public void migrateUp() {
        Deque<Migration> batch = new ArrayDeque<>();
        try {
            for (Migration m : pending) {
                System.out.println("[" + m.version() + "] " + m.description());
                m.up();
                batch.push(m);
            }
            applied.addAll(pending);
            pending.clear();
            System.out.println("All migrations applied successfully!");
        } catch (Exception e) {
            System.out.println("FAILED: " + e.getMessage() + " — Rolling back batch...");
            while (!batch.isEmpty()) {
                batch.pop().down();
            }
        }
    }

    public void migrateDown(int n) {
        for (int i = 0; i < n && !applied.isEmpty(); i++) {
            Migration m = applied.remove(applied.size() - 1);
            System.out.println("Rolling back [" + m.version() + "] " + m.description());
            m.down();
        }
    }

    public void getStatus() {
        System.out.println("\n=== Migration Status ===");
        System.out.println("Applied: " + applied.size());
        applied.forEach(m -> System.out.println("  [" + m.version() + "] " + m.description()));
        System.out.println("Pending: " + pending.size());
        pending.forEach(m -> System.out.println("  [" + m.version() + "] " + m.description()));
